def cyk_algorithm(grammar, string):
    '''
    grammar: dict where key is variable and value is list of productions
    string: input string to check membership
    Returns: True if string can be derived from start symbol
    '''
    n = len(string)
    if n == 0:
        # Check if ε can be derived (S → ε in grammar)
        return 'S' in grammar and '' in grammar['S']

    # P[i][j] = set of variables that can derive substring i to j
    P = [[set() for _ in range(n)] for _ in range(n)]

    # Initialize: substrings of length 1
    for i, char in enumerate(string):
        for var, productions in grammar.items():
            if char in productions:
                P[i][i].add(var)

    # Fill table for longer substrings
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            for k in range(i, j):
                # Try all splits: substring i to k and k+1 to j
                for var in grammar:
                    for prod in grammar[var]:
                        if len(prod) == 2:  # A → BC form
                            B, C = prod[0], prod[1]
                            if B in P[i][k] and C in P[k+1][j]:
                                P[i][j].add(var)
                                break

    # Check if start symbol S can derive the entire string
    return 'S' in P[0][n-1]

# Example usage with CNF grammar
gammar = {
    'S': ['AB', ''],  # S → AB, S → ε
    'A': ['a'],       # A → a
    'B': ['b']        # B → b
}
print(cyk_algorithm(grammar, 'ab'))  # True
print(cyk_algorithm(grammar, ''))    # True

#include <stdio.h>
#include <string.h>

// Structure for a production rule
typedef struct {
    char lhs;           // Left-hand side variable
    char rhs[10];       // Right-hand side symbols
    int rhs_len;        // Length of RHS
} Production;

// Function to convert productions with terminals to CNF
void convertToCNF(Production prods[], int *n) {
    char new_vars[26];  // New variables T, U, V...
    int new_var_count = 0;

    for (int i = 0; i < *n; i++) {
        // If RHS has terminal mixed with variables
        if (prods[i].rhs_len > 1) {
            char new_rhs[10] = "";
            int new_len = 0;

            for (int j = 0; j < prods[i].rhs_len; j++) {
                if (prods[i].rhs[j] >= 'a' && prods[i].rhs[j] <= 'z') {
                    // It's a terminal - create/need new variable
                    char new_var = 'T' + new_var_count;
                    // Check if we already have this conversion
                    // Add new production: new_var -> terminal
                    printf("New production: %c -> %c\n", new_var, prods[i].rhs[j]);
                    new_rhs[new_len++] = new_var;
                    new_var_count++;
                } else {
                    // It's a variable - keep as is
                    new_rhs[new_len++] = prods[i].rhs[j];
                }
            }
            strcpy(prods[i].rhs, new_rhs);
            prods[i].rhs_len = new_len;
        }
    }

    // Now split productions with >2 variables
    // A -> BCD becomes A -> XB, X -> CD
}

int main() {
    // Example: Convert S -> aB to CNF
    // Should become: S -> XB, X -> a
    printf("CNF Conversion Example\n");
    convertToCNF(NULL, NULL);
    return 0;
}
